<?php
if (!defined('ABSPATH')) exit;
function cdp_render_licenses_page(){ if(!current_user_can('manage_options')) return; global $wpdb; $l=cdp_table('licenses'); $p=cdp_table('products');
 if(isset($_POST['cdp_add_license'])){ check_admin_referer('cdp_add_license'); $user_id=absint($_POST['user_id']??0); $product_id=absint($_POST['product_id']??0); $plan=sanitize_text_field($_POST['subscription_plan']??''); $qty=max(1,absint($_POST['quantity']??1)); $start=sanitize_text_field($_POST['start_date']??''); $end=sanitize_text_field($_POST['end_date']??''); if($user_id&&$product_id&&get_user_by('id',$user_id)&&$plan&&$start&&$end){ $wpdb->insert($l,['user_id'=>$user_id,'product_id'=>$product_id,'subscription_plan'=>$plan,'quantity'=>$qty,'start_date'=>$start,'end_date'=>$end,'notes'=>sanitize_textarea_field($_POST['notes']??''),'created_by'=>get_current_user_id(),'created_at'=>current_time('mysql'),'updated_at'=>current_time('mysql')]); echo '<div class="updated"><p>License added.</p></div>'; } else echo '<div class="error"><p>Valid user, product, plan, start date, and end date are required.</p></div>'; }
 if(isset($_POST['cdp_delete_license'])){ check_admin_referer('cdp_delete_license'); $wpdb->delete($l,['id'=>absint($_POST['license_id'])]); echo '<div class="updated"><p>License removed.</p></div>'; }
 $products=$wpdb->get_results("SELECT id,title FROM $p ORDER BY title"); $rows=$wpdb->get_results("SELECT l.*, p.title FROM $l l JOIN $p p ON p.id=l.product_id ORDER BY l.id DESC LIMIT 300"); ?>
 <div class="wrap"><h1>Licenses</h1><form method="post"><?php wp_nonce_field('cdp_add_license'); ?><table class="form-table"><tr><th>User ID</th><td><input type="number" name="user_id" required></td></tr><tr><th>Product</th><td><select name="product_id" required><option value="">Select product</option><?php foreach($products as $x) echo '<option value="'.esc_attr($x->id).'">'.esc_html($x->title).'</option>'; ?></select></td></tr><tr><th>Subscription plan</th><td><input name="subscription_plan" class="regular-text" placeholder="Essential / Advanced / Premium" required></td></tr><tr><th>Quantity</th><td><input type="number" name="quantity" min="1" value="1"></td></tr><tr><th>Start date</th><td><input type="date" name="start_date" required></td></tr><tr><th>End date</th><td><input type="date" name="end_date" required></td></tr><tr><th>Notes</th><td><textarea name="notes" class="large-text" rows="2"></textarea></td></tr></table><p><button class="button button-primary" name="cdp_add_license" value="1">Add License</button></p></form>
 <h2>Recent Licenses</h2><table class="widefat striped"><thead><tr><th>ID</th><th>User</th><th>Product</th><th>Plan</th><th>Qty</th><th>Start</th><th>End</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach($rows as $r): $u=get_user_by('id',$r->user_id); ?><tr><td><?php echo esc_html($r->id); ?></td><td><?php echo esc_html($u?$u->user_login.' (#'.$r->user_id.')':'#'.$r->user_id); ?></td><td><?php echo esc_html($r->title); ?></td><td><?php echo esc_html($r->subscription_plan); ?></td><td><?php echo esc_html($r->quantity); ?></td><td><?php echo esc_html($r->start_date); ?></td><td><?php echo esc_html($r->end_date); ?></td><td><?php echo esc_html(cdp_status_for_dates($r->start_date,$r->end_date)); ?></td><td><form method="post"><?php wp_nonce_field('cdp_delete_license'); ?><input type="hidden" name="license_id" value="<?php echo esc_attr($r->id); ?>"><button class="button" name="cdp_delete_license" value="1">Remove</button></form></td></tr><?php endforeach; ?></tbody></table></div><?php }
